INSERT INTO messages (conversation_id, role, content, created_at, query) VALUES (13, 'ai', 'รับทราบแล้วค่า เรื่องระบบล่มและเข้าใช้งานไม่ได้ นิวเปิดตั๋วงานด่วนให้เรียบร้อยเลยนะคะ หมายเลข Ticket คือ TCK-2026-59293 ทีมงานจะดูแลแก้ไขให้เสร็จภายใน 4 ชั่วโมงค่ะ
INSERT INTO messages (conversation_id, role, content, created_at, query) VALUES (13, 'ai', 'อ่าค่ะ เรื่องการขอเบิกอุปกรณ์ IT นิวขอตรวจสอบขั้นตอนให้ชัดเจนก่อนนะคะ เพื่อให้ไม่พลาดรายละเอียดสำคัญเลย เดี๋ยวเปิด ticket ให้ทีมที่ดูแลเรื่องนี้มาตอบโดยตรงเลยค่ะ รอสักครู่นะคะเปิดตั๋วสอบถามเรื่องขั้นตอนขอเบิกอุปกรณ์ IT ให้นะคะ 📋 หมายเลข Ticket คือ TCK-2026-41725 ค่ะ ทีมงานจะติดต่อกลับพร้อมรายละเอียดภายใน 7 วันทำการนี้เลยค่ะ ถ้ามีอะไรอยากให้ช่วยระหว่างนี้ทักมาได้เลยนะคะ 😊', NULL, NULL);
